import{_ as e,o,c as s,a0 as t}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"NEXUS Runtime Canônico — Contrato Operacional","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_RUNTIME.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_RUNTIME.md","lastUpdated":1783623176000}'),n={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_RUNTIME.md"};function i(r,a,d,c,l,p){return o(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="nexus-runtime-canonico-—-contrato-operacional" tabindex="-1">NEXUS Runtime Canônico — Contrato Operacional <a class="header-anchor" href="#nexus-runtime-canonico-—-contrato-operacional" aria-label="Permalink to &quot;NEXUS Runtime Canônico — Contrato Operacional&quot;">​</a></h1><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Este documento define o contrato operacional do runtime NEXUS vigente. Ele descreve o fluxo de dados, as responsabilidades de cada substrato e as três primitivas MCP que compõem o núcleo da interação agente-sistema. Não substitui <code>docs/T4_GRAPH_NORMS.md</code> (navegação) nem <code>AGENTS.md</code> (protocolo do agente), mas as amarra num fluxo único.</p><h2 id="as-tres-primitivas-de-runtime" tabindex="-1">As Três Primitivas de Runtime <a class="header-anchor" href="#as-tres-primitivas-de-runtime" aria-label="Permalink to &quot;As Três Primitivas de Runtime&quot;">​</a></h2><h3 id="nexus-query-—-entrada-por-similaridade-semantica-t3" tabindex="-1">nexus_query — Entrada por Similaridade Semântica (T3) <a class="header-anchor" href="#nexus-query-—-entrada-por-similaridade-semantica-t3" aria-label="Permalink to &quot;nexus_query — Entrada por Similaridade Semântica (T3)&quot;">​</a></h3><p>A porta de entrada do runtime. Uma query em linguagem natural é embedada (<code>nomic-embed-text</code>, 768d) e busca no Qdrant coleção <code>nexus_ghost</code>.</p><ul><li><strong>Alvo:</strong> L2 (sumário semântico) via similaridade coseno</li><li><strong>Triangulação:</strong> Quando <code>triangulate=true</code>, o coordinator cruza os resultados L2 com os equivalentes L1 (AST) e L0 (código-fonte) do mesmo blob, retornando um pack tri-nível</li><li><strong>Disclaimer:</strong> a busca é por proximidade semântica, não por matching estrutural. Para busca estrutural, use <code>collection=&#39;nexus_ast&#39;</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_query(&quot;auth guard redirect&quot;, triangulate=true)</span></span>
<span class="line"><span>  → pack: L2 semântico + L1 AST + L0 código-fonte</span></span></code></pre></div><h3 id="nexus-adjacent-—-expansao-topologica-t4" tabindex="-1">nexus_adjacent — Expansão Topológica (T4) <a class="header-anchor" href="#nexus-adjacent-—-expansao-topologica-t4" aria-label="Permalink to &quot;nexus_adjacent — Expansão Topológica (T4)&quot;">​</a></h3><p>A partir de um <code>node_id</code> (UUID de qualquer nó no grafo T4), navega pelas arestas do grafo multi-relacional.</p><ul><li><strong>Subir:</strong> adjacent(chunk) → <code>part_of</code> → file node</li><li><strong>Descer:</strong> adjacent(file_node) → inbound <code>part_of</code> → lista de chunks</li><li><strong>Cruzar:</strong> adjacent(file_node) → <code>depends_on:imports</code> → arquivos importados</li><li><strong>Projeção tri-axial:</strong> <code>criteria</code> × <code>file_type</code> × <code>project</code> — cada chamada fatia o grafo num ângulo específico</li></ul><p>Para a especificação completa dos tipos de aresta, padrões de navegação e eixos de projeção, consulte <code>docs/T4_GRAPH_NORMS.md</code>.</p><h3 id="nexus-link-—-cristalizacao-estigmergica" tabindex="-1">nexus_link — Cristalização Estigmérgica <a class="header-anchor" href="#nexus-link-—-cristalizacao-estigmergica" aria-label="Permalink to &quot;nexus_link — Cristalização Estigmérgica&quot;">​</a></h3><p>Registra uma descoberta não-óbvia entre dois nós no grafo T4 como uma aresta <code>semantic_bridge</code> com decaimento temporal (<code>expires_at</code>).</p><ul><li><strong>Quando usar:</strong> após completar uma investigação multi-hop em que o agente descobre uma relação que não está capturada por <code>depends_on:imports</code></li><li><strong>Comportamento:</strong> arestas sem tráfego futuro evaporam (decaimento ativo). A cristalização precisa ser confirmada por uso — é um contrato fraco, intencionalmente</li><li><strong>Contrapartida:</strong> para fatos estruturais (ex: &quot;arquivo A importa B&quot;), não use <code>nexus_link</code> — isso é função do pipeline L1</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_query(&quot;...&quot;) → node_id A</span></span>
<span class="line"><span>  → nexus_adjacent(A) → node_id B</span></span>
<span class="line"><span>  → nexus_link(A, B, criteria=&quot;semantic_bridge&quot;, rationale=&quot;...&quot;)</span></span></code></pre></div><h2 id="mcp-tools-expostas" tabindex="-1">MCP Tools Expostas <a class="header-anchor" href="#mcp-tools-expostas" aria-label="Permalink to &quot;MCP Tools Expostas&quot;">​</a></h2><p>O servidor MCP (<code>http://localhost:7474/sse</code> para conexão remota, ou stdio via <code>nexus_mcp_server.py</code>) expõe as seguintes tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Runtime Primitive</th><th>Uso</th></tr></thead><tbody><tr><td><code>nexus_query</code></td><td>Entrada T3</td><td>Busca semântica com triangulação</td></tr><tr><td><code>nexus_adjacent</code></td><td>Expansão T4</td><td>Navegação topológica no grafo</td></tr><tr><td><code>nexus_link</code></td><td>Cristalização</td><td>Escrita de arestas estigmérgicas</td></tr><tr><td><code>nexus_reflections</code></td><td>Consulta L3</td><td>Leitura de insights arquiteturais</td></tr><tr><td><code>nexus_arch_map</code></td><td>Mapa estrutural</td><td>Geração de ARCHITECTURE-MAP.md</td></tr><tr><td><code>nexus_insight</code></td><td>Decisões</td><td>Consulta a decision records persistentes</td></tr></tbody></table><h2 id="query-path-fluxo-de-execucao" tabindex="-1">Query Path (Fluxo de Execução) <a class="header-anchor" href="#query-path-fluxo-de-execucao" aria-label="Permalink to &quot;Query Path (Fluxo de Execução)&quot;">​</a></h2><p>Toda consulta do runtime segue o mesmo pipeline de 5 etapas:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. QUERY É EMBEDADA</span></span>
<span class="line"><span>   └─ nomic-embed-text (768d) → vetor denso</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. T3 LOCALIZA SEMENTES</span></span>
<span class="line"><span>   └─ Qdrant, coleção nexus_ghost → top-k L2 por similaridade coseno</span></span>
<span class="line"><span>   └─ (opcional) collection=&#39;nexus_ast&#39; para busca estrutural L1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. T4 EXPANDE VIA ADJACENT</span></span>
<span class="line"><span>   └─ coordinator recebe chunk_ids → nexus_adjacent() em cada semente</span></span>
<span class="line"><span>   └─ sobe (part_of) → file node → cruza (depends_on:imports) → desce (part_of)</span></span>
<span class="line"><span>   └─ subgrafo ativo é montado na janela da consulta</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. T2 HIDRATA CONTEÚDO</span></span>
<span class="line"><span>   └─ PostgreSQL: abstractions, blobs, agent_links, reflections</span></span>
<span class="line"><span>   └─ hidrata: caminho, versão, chunk_index, metadados, arestas vivas</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. COORDINATOR MATERIALIZA PACKS</span></span>
<span class="line"><span>   └─ estrutura final: { L2 semântico, L1 AST, L0 fonte, metadados T4 }</span></span>
<span class="line"><span>   └─ retorno para o agente via MCP</span></span></code></pre></div><h2 id="responsabilidades-de-cada-substrato" tabindex="-1">Responsabilidades de Cada Substrato <a class="header-anchor" href="#responsabilidades-de-cada-substrato" aria-label="Permalink to &quot;Responsabilidades de Cada Substrato&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Substrato</th><th>Camada</th><th>Função</th></tr></thead><tbody><tr><td><strong>Qdrant</strong></td><td>T3</td><td>Entrada por proximidade vetorial. Coleções <code>nexus_ghost</code> (L0+L2) e <code>nexus_ast</code> (L1). Busca por similaridade coseno.</td></tr><tr><td><strong>PostgreSQL</strong></td><td>T2 + T4</td><td>Âncora canônica de identidade (<code>abstractions</code>, <code>blobs</code>), versionamento (<code>superseded_by_id</code>), arestas topológicas (<code>agent_links</code>), e memória derivada (<code>reflections</code>, <code>architectural_insights</code>).</td></tr><tr><td><strong>Filesystem</strong></td><td>T1</td><td>Fonte material reconstruível. T1 vence em caso de divergência entre substratos (reingestão a partir do fs).</td></tr></tbody></table><h2 id="pipeline-de-enriquecimento" tabindex="-1">Pipeline de Enriquecimento <a class="header-anchor" href="#pipeline-de-enriquecimento" aria-label="Permalink to &quot;Pipeline de Enriquecimento&quot;">​</a></h2><p>A ingestão de novos artefatos segue uma esteira sequencial determinística:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>file watcher (inotify/poll)</span></span>
<span class="line"><span>  → L0 chunking (~2000 chars, overlap)</span></span>
<span class="line"><span>    → L1 AST (ast-grep, blob completo → JSON determinístico)</span></span>
<span class="line"><span>      → L2 enrichment (qwen2.5-coder:1.5b, L0 + L1 → sumário semântico)</span></span>
<span class="line"><span>        → T3 sync (Qdrant: nexus_ghost + nexus_ast)</span></span>
<span class="line"><span>          → T4 edge computation (agent_links: part_of, depends_on:imports,</span></span>
<span class="line"><span>               semantic_bridge, contradicts)</span></span></code></pre></div><p><strong>L3 não é mais produzido por blob.</strong> A síntese de domínio emerge de forma orgânica via <strong>community detection</strong> no grafo T4 (<code>agent_links</code>), utilizando algoritmos como LPA ou walktrap. Cada cluster detectado = candidato a domínio L3. A geração pode ser fixa (armazenada) ou on-the-fly (sintetizada no momento da consulta). Consulte <code>docs/adr/0015-zoom-stateful-protocol.md</code> para a justificativa completa.</p><h2 id="regras-operacionais" tabindex="-1">Regras Operacionais <a class="header-anchor" href="#regras-operacionais" aria-label="Permalink to &quot;Regras Operacionais&quot;">​</a></h2><ol><li><strong>T1 vence em divergência:</strong> Se o conteúdo no filesystem discordar do que está no Postgres ou Qdrant, o filesystem é a fonte da verdade. Reingestão total a partir de T1 é o mecanismo de correção.</li><li><strong>Reingestão total é mecanismo aceitável:</strong> Mudança de modelo de embedding, topologia ou geometria pode exigir <code>TRUNCATE blobs CASCADE</code>, limpeza das coleções Qdrant e reingestão completa.</li><li><strong>Sem suporte prioritário a legados:</strong> O runtime atual não mantém compatibilidade retroativa com formatos de resposta anteriores. Agentes devem usar as primitivas MCP — não endpoints REST legados.</li><li><strong>Stateless por chamada:</strong> Cada tool MCP é independente. Não há estado de sessão entre chamadas — o grafo T4 e o Qdrant são a memória.</li><li><strong>Evaporação estigmérgica:</strong> arestas criadas por <code>nexus_link</code> têm <code>expires_at</code>. Se nenhum agente transitar por elas, evaporam. A memória do runtime é viva, não cumulativa.</li></ol><h2 id="referencias-cruzadas" tabindex="-1">Referências Cruzadas <a class="header-anchor" href="#referencias-cruzadas" aria-label="Permalink to &quot;Referências Cruzadas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Documento</th><th>Conteúdo</th></tr></thead><tbody><tr><td><code>AGENTS.md</code></td><td>As 7 primitivas LLM, protocolo de ativação, navegação T3+T4</td></tr><tr><td><code>docs/CANONICAL_ARCHITECTURE.md</code></td><td>Camadas T1–T6, invariantes arquiteturais, papéis de substrato</td></tr><tr><td><code>docs/T4_GRAPH_NORMS.md</code></td><td>Especificação completa do grafo: nós, arestas, eixos de projeção, padrões de navegação</td></tr><tr><td><code>docs/adr/0015-zoom-stateful-protocol.md</code></td><td>Decisão sobre L3 plástica via comunidades T4</td></tr></tbody></table>`,32)])])}const g=e(n,[["render",i]]);export{m as __pageData,g as default};
